import os
import sqlite3
from pathlib import Path
from typing import Any

import bcrypt
from flask import Flask, jsonify, render_template_string, request
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from flask_talisman import Talisman
from markupsafe import escape

app = Flask(__name__)

# ✅ 修复 #5: 从环境变量读取敏感信息
app.config["SECRET_KEY"] = os.environ.get("SECRET_KEY")
if not app.config["SECRET_KEY"]:
    raise RuntimeError("必须设置 SECRET_KEY 环境变量")

DB_PASSWORD = os.environ.get("DB_PASSWORD", "")

# ✅ 修复 #9: 添加安全响应头
Talisman(
    app,
    force_https=False,  # 开发环境设为 False，生产环境设为 True
    strict_transport_security=True,
    content_security_policy={
        "default-src": "'self'",
        "script-src": "'self'",
        "style-src": "'self' 'unsafe-inline'",
    },
)

# ✅ 修复 #10: 添加速率限制
limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"],
    storage_uri="memory://",
)


def get_db() -> sqlite3.Connection:
    """获取数据库连接。"""
    return sqlite3.connect("app.db")


# ✅ 修复 #6: 密码哈希工具函数
def hash_password(password: str) -> str:
    """使用 bcrypt 哈希密码。"""
    return bcrypt.hashpw(password.encode("utf-8"), bcrypt.gensalt()).decode("utf-8")


def verify_password(password: str, hashed: str) -> bool:
    """验证密码与哈希是否匹配。"""
    return bcrypt.checkpw(password.encode("utf-8"), hashed.encode("utf-8"))


# ✅ 修复 #8: 输入验证函数
def validate_username(username: str | None) -> str | None:
    """验证用户名格式。"""
    if not username:
        return "用户名不能为空"
    if len(username) < 3 or len(username) > 32:
        return "用户名长度必须在 3-32 个字符之间"
    if not username.isalnum():
        return "用户名只能包含字母和数字"
    return None


def validate_password(password: str | None) -> str | None:
    """验证密码格式。"""
    if not password:
        return "密码不能为空"
    if len(password) < 8:
        return "密码长度必须至少 8 个字符"
    return None


@app.route("/login", methods=["POST"])
@limiter.limit("5 per minute")  # ✅ 修复 #10: 登录接口限流
def login() -> tuple[Any, int]:
    """用户登录接口。

    ✅ 修复 #1: 使用参数化查询防止 SQL 注入
    ✅ 修复 #6: 使用 bcrypt 验证密码哈希
    ✅ 修复 #8: 添加输入验证和错误处理
    """
    try:
        username = request.form.get("username", "").strip()
        password = request.form.get("password", "")

        # 输入验证
        if error := validate_username(username):
            return jsonify({"status": "fail", "error": error}), 400

        if error := validate_password(password):
            return jsonify({"status": "fail", "error": error}), 400

        db = get_db()

        # ✅ 使用参数化查询防止 SQL 注入
        query = "SELECT username, password_hash FROM users WHERE username = ?"
        result = db.execute(query, (username,)).fetchone()

        if result and verify_password(password, result[1]):
            return jsonify({"status": "ok", "user": result[0]}), 200

        # 通用错误信息，防止用户枚举
        return jsonify({"status": "fail", "error": "用户名或密码错误"}), 401

    except sqlite3.Error as e:
        app.logger.error(f"数据库错误: {e}")
        return jsonify({"status": "fail", "error": "服务器内部错误"}), 500
    except Exception as e:
        app.logger.error(f"未预期的错误: {e}")
        return jsonify({"status": "fail", "error": "服务器内部错误"}), 500


@app.route("/search")
@limiter.limit("30 per minute")
def search() -> str:
    """搜索接口。

    ✅ 修复 #4: 使用 markupsafe.escape() 防止 XSS
    ✅ 修复 #8: 添加输入验证
    """
    try:
        q = request.args.get("q", "").strip()

        # 输入验证
        if len(q) > 200:
            return render_template_string(
                "<h1>错误</h1><p>搜索查询过长</p>"
            ), 400

        # ✅ 使用 escape() 防止 XSS
        safe_query = escape(q)

        return render_template_string(
            "<h1>搜索结果</h1><p>关键词: {{ query }}</p>",
            query=safe_query,
        )

    except Exception as e:
        app.logger.error(f"搜索错误: {e}")
        return "<h1>错误</h1><p>搜索失败</p>", 500


@app.route("/run")
@limiter.limit("10 per minute")
def run_command() -> tuple[Any, int]:
    """命令执行接口（已安全化）。

    ✅ 修复 #2: 移除任意命令执行，改为白名单安全命令
    """
    try:
        cmd = request.args.get("cmd", "").strip()

        # ✅ 白名单验证：只允许安全命令
        allowed_commands = {
            "ls": ["ls", "-la"],
            "pwd": ["pwd"],
            "date": ["date"],
            "uptime": ["uptime"],
        }

        if cmd not in allowed_commands:
            return jsonify({
                "error": "不允许的命令",
                "allowed": list(allowed_commands.keys()),
            }), 400

        # 使用 subprocess 而非 os.popen，更安全
        import subprocess

        result = subprocess.run(
            allowed_commands[cmd],
            capture_output=True,
            text=True,
            timeout=5,  # 防止命令挂起
            check=False,
        )

        return jsonify({
            "command": cmd,
            "output": result.stdout,
            "stderr": result.stderr,
            "returncode": result.returncode,
        })

    except subprocess.TimeoutExpired:
        return jsonify({"error": "命令执行超时"}), 408
    except Exception as e:
        app.logger.error(f"命令执行错误: {e}")
        return jsonify({"error": "命令执行失败"}), 500


# 定义安全的文件读取目录
SAFE_FILE_DIR = Path("/tmp/hermes-evolution-eval/safe_files")
SAFE_FILE_DIR.mkdir(parents=True, exist_ok=True)


@app.route("/file")
@limiter.limit("20 per minute")
def read_file() -> tuple[str | Any, int]:
    """文件读取接口。

    ✅ 修复 #3: 路径验证，防止路径遍历攻击
    ✅ 修复 #8: 添加错误处理
    """
    try:
        filename = request.args.get("path", "").strip()

        if not filename:
            return jsonify({"error": "缺少 path 参数"}), 400

        # ✅ 路径验证：只允许读取指定目录下的文件
        # 使用 resolve() 解析符号链接和 .. 路径
        requested_path = (SAFE_FILE_DIR / filename).resolve()

        # 检查解析后的路径是否在安全目录内
        if not requested_path.is_relative_to(SAFE_FILE_DIR):
            app.logger.warning(f"路径遍历尝试: {filename}")
            return jsonify({"error": "无效的文件路径"}), 403

        # 检查文件是否存在
        if not requested_path.is_file():
            return jsonify({"error": "文件不存在"}), 404

        # 文件大小限制（防止读取超大文件）
        if requested_path.stat().st_size > 10 * 1024 * 1024:  # 10MB
            return jsonify({"error": "文件过大"}), 413

        # 读取文件
        content = requested_path.read_text(encoding="utf-8", errors="replace")
        return jsonify({
            "filename": requested_path.name,
            "content": content,
        })

    except UnicodeDecodeError:
        return jsonify({"error": "文件编码错误，无法读取"}), 400
    except PermissionError:
        app.logger.error(f"权限不足: {filename}")
        return jsonify({"error": "无权限读取该文件"}), 403
    except Exception as e:
        app.logger.error(f"文件读取错误: {e}")
        return jsonify({"error": "文件读取失败"}), 500


